      this.#content.slice(0, position) +
      text +
      this.#content.slice(position);
  }

  delete(position, length) {
    this.#content =
      this.#content.slice(0, position) +
      this.#content.slice(position + length);
  }

  getContent() { return this.#content; }
}

// Concrete command
