  constructor(editor, text, position) {
    this.editor = editor;
    this.text = text;
    this.position = position;
  }

  execute() {
    this.editor.insert(this.text, this.position);
  }

  undo() {
    this.editor.delete(this.position, this.text.length);
  }
}

